class Solution:
    def longestPalindrome(self, words) -> int:
        counts = [[0] * 26 for _ in range(26)]
        for w in words:
            a = ord(w[0]) - ord('a')
            b = ord(w[1]) - ord('a')
            counts[a][b] += 1
        length = 0
        center_added = False
        for a in range(26):
            for b in range(26):
                if a < b:
                    m = min(counts[a][b], counts[b][a])
                    length += m * 4
                elif a == b:
                    pairs = counts[a][b] // 2
                    length += pairs * 4
                    if counts[a][b] % 2 == 1 and not center_added:
                        length += 2
                        center_added = True
        return length

