from collections import Counter

class Solution:
    def longestPalindrome(self, words: List[str]) -> int:
        cnt = Counter(words)
        length = 0
        for w in list(cnt.keys()):
            if cnt[w] <= 0:
                continue
            r = w[::-1]
            if w == r:
                pairs = cnt[w] // 2
                length += pairs * 4
                cnt[w] -= pairs * 2
            elif r in cnt and w < r:
                m = min(cnt[w], cnt[r])
                length += m * 4
                cnt[w] -= m
                cnt[r] -= m
        for w, c in cnt.items():
            if c > 0 and w == w[::-1]:
                length += 2
                break
        return length

