var longestPalindrome = function(words) {
    const cnt = new Map();
    for (const w of words) {
        cnt.set(w, (cnt.get(w) || 0) + 1);
    }
    let length = 0;
    const keys = Array.from(cnt.keys());
    for (const w of keys) {
        const c = cnt.get(w);
        if (c <= 0) continue;
        const r = w.split('').reverse().join('');
        if (w === r) {
            const pairs = Math.floor(c / 2);
            length += pairs * 4;
            cnt.set(w, c - pairs * 2);
        } else if (cnt.has(r) && w < r) {
            const m = Math.min(c, cnt.get(r));
            length += m * 4;
            cnt.set(w, c - m);
            cnt.set(r, cnt.get(r) - m);
        }
    }
    for (const [w, c] of cnt) {
        if (c > 0 && w === w.split('').reverse().join('')) {
            length += 2;
            break;
        }
    }
    return length;
};
